parameters.jsCode:
let raw = $json.choices[0].message.content;
let parsed = {};
try {
  parsed = JSON.parse(raw);
} catch(e) {
  parsed = { erro: "Falha ao parsear JSON do DeepSeek" };
}

// Montar o payload fundindo a entrada com o resultado da IA 1
const input = $('Execute Workflow Trigger').item.json.payload_json || $('Execute Workflow Trigger').item.json;
input.diagnostico = parsed;

return { json: input };
